sp_widget.client_script:
api.controller=function($rootScope, $scope, $timeout, $sce, spUtil, $log, $location, i18n) {
  /* widget controller */
  var c = this;
	var dtech_tasker_common = x_153465_discovert.dtech_tasker_common;

	c.CONST_LEFT_NAV_MIN_WIDTH = 144;
	c.CONST_LEFT_NAV_MAX_WIDTH = 410;
	c.CONST_CHEVRON_WIDTH = 16;

	var shared = {};

	main();

	function main(){
		_loadTaskPages();
		c.data.leftNavigationWidth	= c.CONST_LEFT_NAV_MIN_WIDTH;
	}


	$scope.$watch('$viewContentLoaded', function(){
		_updateWidth();
		$scope.$parent.$parent.toggleLeftNavigation();
	});

	$scope.toggleOpen = function(){
		c.data.isOpen = !c.data.isOpen;
		_updateWidth();
		$scope.$parent.$parent.toggleLeftNavigation();

	};

	$scope.openFilter = function(){
		$location.search('sys_id', null);
		$location.search('table', null);
		$scope.$parent.$parent.changeAppContext(dtech_tasker_common.CONSTANTS.APP_CONTEXTS.HOME_FILTER);
	}

	$scope.openOrganization = function(){
		$location.search('sys_id', null);
		$location.search('table', null);
		$scope.$parent.$parent.changeAppContext(dtech_tasker_common.CONSTANTS.APP_CONTEXTS.ORGANIZATION);
	}

	$scope.openTask = function(){
		$location.search('sys_id', null);
		$location.search('table', null);
		$scope.$parent.$parent.changeAppContext(dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TASK);
	}

	$scope.openTemplates = function(){
		$location.search('sys_id', null);
		$location.search('table', null);
		$scope.$parent.$parent.changeAppContext(dtech_tasker_common.CONSTANTS.APP_CONTEXTS.TEMPLATE);
	}

	function _loadTaskPages(){
		var taskPages = [];
		taskPages.push(_initTaskPage("my_task_home_page", c.data.messages["My Tasks"], "x_153465_discovert.DueTask_Light24.svg"));
		taskPages.push(_initTaskPage("my_ous_tasks_home_page", c.data.messages["My OU's Tasks"], "x_153465_discovert.DueTask_Light24.svg"));
		c.data.taskPages = taskPages;
	}

	function _initTaskPage(name,caption,src){
		var taskPage = {}
		taskPage.name= name;
		taskPage.caption = i18n.getMessage(caption);
		taskPage.src = src;
		taskPage.isSelected= name == c.data.task_page_name;
		return taskPage;
	}

	function _updateWidth(){
		var tasker_left_navigation_header = document.getElementById('tasker_left_navigation_header');
		var tasker_left_navigation_body = document.getElementById('tasker_left_navigation_body');
		var tasker_left_navigation_collapse = document.getElementById('tasker_left_navigation_collapse');
		if(c.data.isOpen!=true){
			tasker_left_navigation_header.style.width = c.CONST_LEFT_NAV_MIN_WIDTH + "px";
			tasker_left_navigation_body.style.width = c.CONST_LEFT_NAV_MIN_WIDTH + "px";
			tasker_left_navigation_collapse.style.left = c.CONST_LEFT_NAV_MIN_WIDTH + "px";
			c.data.leftNavigationWidth=c.CONST_LEFT_NAV_MIN_WIDTH;
		} else {
			tasker_left_navigation_header.style.width = c.CONST_LEFT_NAV_MAX_WIDTH + "px";
			tasker_left_navigation_body.style.width = c.CONST_LEFT_NAV_MAX_WIDTH + "px";
			tasker_left_navigation_collapse.style.left = c.CONST_LEFT_NAV_MAX_WIDTH + "px";
			c.data.leftNavigationWidth=c.CONST_LEFT_NAV_MAX_WIDTH;
		}
	}

	$scope.alignIcons = function(){
		var justify_content = "justify-center";
		if(c.data.isOpen){
			justify_content="justify-start";
		}
		return justify_content;
	};	
};

sp_widget.css:
.dtech-left-navigation{
  background-color:#182024;
}

.dtech-btn-collapse{
  background-color: #293136;
  color:#FFFFFF;
  padding: 14px 5px;
  z-index:2; // needs zindex b/c it is sitting on drop shadow, needs to b3 2 b/c middle section is 1
  border-radius: 0px 5px 5px 0px;
  position:absolute;
  top:10px;
}

.dtech-btn-collapse:hover{
  background-color:#0087D2;
  border-left:none;
  border: 1px #0087D2;
  border-style: solid solid solid none;
}

.dtech-btn-collapse:focus{
  background-color:#0087D2;
  border-left:none;
  border: 1px #0087D2;
  border-style: solid solid solid none;
}

// matches height of viewer header
.dtech-left-navigation-header {
  padding: 20px 30px 20px 30px;
  background-color:#293136;
}

.dtech-left-nav-divider{
  border-bottom: 1px solid #363E43;
  margin: 0px 10px 0px 10px;
}

.dtech-left-nav-selector{
  margin:10px;
  border-radius: 5px;
  padding: 0px 20px 0px 20px;
}
  .dtech-left-nav-button;
}

.dtech-left-nav-filter{
  padding: 0px 50px 10px 20px;
  margin: 0px -20px 0px -20px;
}

.dtech-left-nav-button, .dtech-left-nav-selector, .dtech-left-nav-filter {
  display:flex;
  flex-wrap:nowrap;
  color:#FFFFFF;
  align-items:center;
  min-width:124px;
  height: 48px;
  opacity:75%;  
  cursor: pointer;
  text-wrap:nowrap;
}

.dtech-left-nav-button:hover, .dtech-left-nav-selector:hover, .dtech-left-nav-filter:hover{
  opacity:100%;
  background-color:#00A4FF;
}

.dtech-left-nav-button:selected, .dtech-left-nav-selector:selected, .dtech-left-nav-filter:selected{
  opacity:100%;
  background-color:#045797;
}

.dtech-left-nav-button:focus, .dtech-left-nav-selector:focus, .dtech-left-nav-filter:focus{
  border: 2px solid #0087D2;
  background-color:none;
}

.dtech-left-nav-task-top{
  color:#FFFFFF;
  padding: 20px 0px 0px 0px;
  display:flex;
  flex-direction:row;
  align-items: center;
  background-color:#293136;
}

.dtech-right-button-left-margin{
  margin-left:10px;
}

.dtech-left-nav-task-top-button{
  background-color:#293136;
  border-width: 5px;
  border-style: solid none none none;
  border-color:#293136;
  border-radius: 5px 5px 0px 0px;
  margin-left:10px;
  padding:10px;
  opacity:75%;
  display: flex;
  flex-wrap: nowrap;
  align-items: center;
}

.dtech-left-nav-task-top-button:hover{  
  border-color: #182024;
  background-color:#182024;
  opacity:100%;
}

.dtech-left-nav-task-top-button-selected{
  background-color:#182024;
  opacity:100%;
  border-color: #00A4FF;
}

.tasker-left-nav-count-circle{
  border-radius:50%;
  height: 16px;
  min-width: 16px;
  background-color:#FFFFFF;
  opacity:25%;
}

.tasker-left-nav-count-text{
  color: #FFFFFF;
  text-align:center;
  vertical-align:middle;
}

