// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: Tasker Left Navigation
// COMPANY: Discover Technologies
(function ($sp, input, data, options, gs) {
	// declare globally so they are loaded once in the main function
	var tsss;
	var OUsWhereIamAMember;
	var OUsWhereIamAMemberAdmin;
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */
	main();
	function main(){
		data.appContext = (input || {}).appContext || (options || {}).appContext || "";
		data.table = (input || {}).table || (options || {}).table || $sp.getParameter("table") || "";
		data.sys_id = (input || {}).sys_id || (options || {}).sys_id || $sp.getParameter("sys_id") || $sp.getParameter("sl_sys_id");

		_loadMessages();
		tsss =  new x_153465_discovert.tasking_System_Settings_Scripts();
		OUsWhereIamAMember = tsss.getOUsWhereIamAMember();
		// DFCT0010732
		OUsWhereIamAMemberAdmin = tsss.getMyOUMemberAdmins();

		var page_filter;
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('tasker_left_navigation');
		// not loading messages or icons, just loading default home page
		data.task_page_name = taskWidgetIconsAndMessage.getPreferenceUserDefaultLandingPage();
	}

	function _loadMessages(){
		data.messages = {};
		data.messages["My Tasks"]=gs.getMessage("My Tasks");
		data.messages["My OU's Tasks"]= gs.getMessage("My OU's Tasks");
	}

})($sp, input, data, options, gs);
